import{_ as l,c as i,o as e,ag as t}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"daily/javaScript-01-简介、脚本的引入.md","filePath":"daily/javaScript-01-简介、脚本的引入.md"}'),s={name:"daily/javaScript-01-简介、脚本的引入.md"};function r(c,a,d,n,o,_){return e(),i("div",null,a[0]||(a[0]=[t('<h2 id="js-异步加载的方式有哪些" tabindex="-1">JS 异步加载的方式有哪些？ <a class="header-anchor" href="#js-异步加载的方式有哪些" aria-label="Permalink to &quot;JS 异步加载的方式有哪些？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>script 标签的 defer 属性</li><li>script 标签的 async 属性</li><li>动态插入 script 脚本</li></ul></details><h2 id="script-标签的-defer-和-async-属性的区别是什么" tabindex="-1">script 标签的 defer 和 async 属性的区别是什么？ <a class="header-anchor" href="#script-标签的-defer-和-async-属性的区别是什么" aria-label="Permalink to &quot;script 标签的 defer 和 async 属性的区别是什么？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>defer 属性 <ul><li>加载：带有 defer 属性的脚本会异步加载，浏览器在解析 HTML 文档的同时会加载脚本。</li><li>执行时机：脚本的执行会被推迟到整个 HTML 文档完全解析完毕之后，即 DOM 树完全构建之后，且在 DOMContentLoaded 事件触发之前执行。</li><li>执行顺序：如果有多个带 defer 属性的脚本，它们会按照在文档中出现的顺序依次执行。</li></ul></li><li>async 属性 <ul><li>加载：带有 async 属性的脚本同样会异步加载，浏览器在解析 HTML 文档的同时会加载脚本。</li><li>执行时机：一旦脚本加载完成，浏览器会立即执行它，不会等待 HTML 文档的解析完成。</li><li>执行顺序：如果有多个带 async 属性的脚本，它们的执行顺序无法保证，取决于各个脚本加载完成的顺序。</li></ul></li><li>使用场景 <ul><li>defer 适用于需要确保脚本在 DOM 完全构建之后执行的情况，通常用于依赖 DOM 结构的脚本。</li><li>async 适用于独立的脚本，比如分析或广告脚本，这些脚本不依赖于 DOM 结构或其他脚本的执行顺序。</li></ul></li></ul></details>',4)]))}const m=l(s,[["render",r]]);export{p as __pageData,m as default};
